async function main() {
  console.log('Очищаем старые данные...')

  // Удаляем статьи из старых стоматологических категорий
  await prisma.articleTag.deleteMany({
    where: { article: { category: { slug: { in: ['bolezni-dyosen', 'profilaktika', 'detskaya', 'zapah-izo-rta'] } } } }
  })
  await prisma.article.deleteMany({
    where: { category: { slug: { in: ['bolezni-dyosen', 'profilaktika', 'detskaya', 'zapah-izo-rta'] } } }
  })
  await prisma.category.deleteMany({
    where: { slug: { in: ['bolezni-dyosen', 'profilaktika', 'detskaya', 'zapah-izo-rta'] } }
  })

  console.log('Создаём категории...')
  for (const cat of categories) {
    await prisma.category.upsert({
      where: { slug: cat.slug },
      update: cat,
      create: cat,
    })
  }

  console.log('Создаём автора...')
  const author = await prisma.author.upsert({
    where: { slug: 'doktor-ivanov' },
    update: {},
    create: {
      name: 'Иванов Сергей Юрьевич',
      specialty: 'Медицинский специалист',
      bio: 'Практикующий врач с многолетним опытом. Автор научных публикаций по клинической медицине.',
      slug: 'doktor-ivanov',
    },
  })

  console.log('Создаём статьи...')
  let created = 0
  for (const article of articles) {
    const category = await prisma.category.findUnique({ where: { slug: article.categorySlug } })
    if (!category) {
      console.log('Категория не найдена:', article.categorySlug)
      continue
    }

    // Создаём теги
    const tagRecords = []
    for (const tagName of article.tags) {
      const tagSlug = tagName.toLowerCase().replace(/[^a-zа-яё0-9]+/gi, '-').replace(/^-+|-+$/g, '')
      const tag = await prisma.tag.upsert({
        where: { slug: tagSlug },
        update: {},
        create: { title: tagName, slug: tagSlug },
      })
      tagRecords.push(tag)
    }

    // Проверяем существование статьи
    const existing = await prisma.article.findUnique({ where: { slug: article.slug } })
    if (existing) {
      console.log('Уже существует:', article.slug)
      continue
    }

    await prisma.article.create({
      data: {
        title: article.title,
        slug: article.slug,
        excerpt: article.excerpt,
        content: article.content,
        isPublished: true,
        publishedAt: new Date(Date.now() - Math.floor(Math.random() * 30) * 24 * 60 * 60 * 1000),
        authorId: author.id,
        categoryId: category.id,
        viewCount: Math.floor(Math.random() * 200) + 10,
        tags: {
          create: tagRecords.map(tag => ({ tagId: tag.id }))
        }
      }
    })
    created++
    process.stdout.write('.')
  }

  console.log(`\nГотово! Создано статей: ${created}`)

  // Администратор уже создан через change-password.ts — пропускаем
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect())
